var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"후후, 어울리나요?","JPN":"ふふ、似合っていますか？","ENG":"Hehe, how does it look?","TWN":"呵呵，合適嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"내가 보는 눈이 좀 있지. 아주 잘 어울려.","JPN":"妾の目に狂いはない。よく似合っているぞ。","ENG":"It looks great. And you can take my word for it.","TWN":"我的眼光不會錯的，一定很適合她。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유. 다 갈아 입었니?","JPN":"千冬。着替え終わったの？","ENG":"Chifuyu, are you done changing?","TWN":"千冬，你換好了嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어머.","JPN":"あら。","ENG":"Oh my.","TWN":"哇……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우와아……","JPN":"うわあ……","ENG":"Wow...","TWN":"哇……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"대, 대단한데, 이 손님?","JPN":"お、お客さん、すごいよ。","ENG":"Th-this customer looks amazing!","TWN":"這會客人，厲害喔？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"손님 정말 예뻐요!","JPN":"お客さん、本当にキレイです！","ENG":"You look beautiful!","TWN":"客人好漂亮！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"이건……","JPN":"これは……","ENG":"This is...","TWN":"這件衣服……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"통기성이 아주 좋은 옷이군요.","JPN":"とても通気性に優れた服ですね。","ENG":"A very breathable fabric.","TWN":"非常透氣呢。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"게다가…… 묘하게 몸이 식는 기분입니다.","JPN":"それに……妙に体が冷めるような気がします。","ENG":"And... it seems to cool my body as well.","TWN":"而且…有種涼感的感覺。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그렇지? 옷에 특별한 마법을 부여해서 열을 조절할 수 있을 거야.","JPN":"だろう？　服に特別な魔法を加えたから、熱を調節できるはずだ。","ENG":"Yeah? I put a spell on the outfit, so it should help you moderate your temperature.","TWN":"對吧？衣服上有特殊的魔法，可以調節溫度。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아까 우리가 잡은 녀석한테서 나온 재료가 핵심이었어.","JPN":"さっき妾たちがやっつけた奴から出た材料が効いている。","ENG":"The material we got from that C.O. was key.","TWN":"剛才我們逮到的那個傢伙身上的材料是關鍵。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"감사합니다. 이 은혜를 어떻게 갚아야 할지……","JPN":"ありがとうございます。どうお礼をしたらいいか……","ENG":"Thank you. I do not know how I can repay you...","TWN":"謝謝你，我不知道該如何報答這份恩情……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"됐어. 내가 그냥 만들어주고 싶었던 옷이었으니까.","JPN":"お礼はいい。ただこの服を妾が作ってみたかっただけだから。","ENG":"It's fine. I just wanted to make one for you.","TWN":"不用，是我自己想做給你的。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머?","JPN":"あら？","ENG":"Oh?","TWN":"喔？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그러니까…… 크흠. 카페 차원에서 협찬한 걸로 치자고","JPN":"だから……コホン。カフェが提供したことにしようではないか。","ENG":"I mean... Ahem. Let's just say we're sponsoring you.","TWN":"所以……咳咳，就當作是咖啡廳贊助你的吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"의상이 아주 만족스러웠나 봐, 라우라?","JPN":"衣装がとても気に入ったのね、ラウラ。","ENG":"Sounds like you're really happy with the outfit, Laura.","TWN":"蘿拉，看來你對這件衣服很滿意喔？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당연한 소리를 가지고 자꾸 그럴래?","JPN":"当たり前のことを何度も言うな。","ENG":"Are you going to continue stating the obvious?","TWN":"可以不要一直說廢話嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"옆에서 계속 초 칠 거면 너도 얼른 가서 손님들 주문이나 받아.","JPN":"隣でずっと水をさすつもりなら、汝も早く行ってお客さんの接待でもしろ。","ENG":"Go join the others and take orders instead of ruining the mood.","TWN":"要是你再說這些有的沒的，那你也去替客人點餐吧。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"손님들, 축제에 간댔지?","JPN":"汝たち、お祭りに行くのだろう？","ENG":"You said you were going to the festival, right?","TWN":"你們是要去參加活動對吧？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"장담하건대, 손님들이 그 축제에서 제일 주목받는 사람들일 거야.","JPN":"妾が保障する。汝らがそのお祭りで一番注目を浴びるだろう。","ENG":"I can guarantee that you two will be the belles of the ball.","TWN":"我敢保證，你們一定會成為活動裡最耀眼的人。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"사람들이 옷에 관심을 보이면 카페 홍보나 좀 부탁해.","JPN":"服に興味がありそうな人にカフェの宣伝をよろしく頼む。","ENG":"If people are interested in the outfit, help promote the cafe.","TWN":"要是有人對這件衣服有興趣，你們就幫我們宣傳一下咖啡廳。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그게 내가 당신들한테 받는 대가야.","JPN":"それが汝らが妾に払う代価だ。","ENG":"That's the price of the costume.","TWN":"這就是我的報酬。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"감사합니다. 라우라 님.","JPN":"ありがとうございます、ラウラ様。","ENG":"Thank you, Miss Laura.","TWN":"謝謝你，蘿拉。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"}}}}]`);export{e as default};